"use client";

import { ArrowRight, Loader2 } from "lucide-react";
import Link from "next/link";
import { useRouter } from "next/navigation";
import { type FormEvent, useState } from "react";
import { createClient } from "@/lib/supabase/client";

const DEFAULT_NEXT_PATH = "/";
const MIN_PASSWORD_LENGTH = 6;

type AuthMode = "sign-in" | "sign-up";

function getSafeNextPath(): string {
  if (typeof window === "undefined") {
    return DEFAULT_NEXT_PATH;
  }

  const rawNextPath = new URLSearchParams(window.location.search).get("next");
  if (!rawNextPath) {
    return DEFAULT_NEXT_PATH;
  }

  try {
    const candidateUrl = new URL(rawNextPath, window.location.origin);
    if (candidateUrl.origin !== window.location.origin) {
      return DEFAULT_NEXT_PATH;
    }

    return `${candidateUrl.pathname}${candidateUrl.search}${candidateUrl.hash}`;
  } catch {
    return DEFAULT_NEXT_PATH;
  }
}

function getEmailRedirectTo(nextPath: string): string | undefined {
  if (typeof window === "undefined") {
    return undefined;
  }

  const callbackUrl = new URL("/auth/callback", window.location.origin);
  callbackUrl.searchParams.set("next", nextPath);
  return callbackUrl.toString();
}

function getErrorMessage(error: unknown): string {
  if (error instanceof Error) {
    if (error.message.includes("NEXT_PUBLIC_SUPABASE")) {
      return "Add NEXT_PUBLIC_SUPABASE_URL and NEXT_PUBLIC_SUPABASE_ANON_KEY before using auth.";
    }

    return error.message;
  }

  return "Authentication failed. Try again.";
}

export default function LoginPage() {
  const router = useRouter();
  const [mode, setMode] = useState<AuthMode>("sign-in");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [statusMessage, setStatusMessage] = useState<string | null>(null);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);

  async function handleSubmit(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();
    setStatusMessage(null);
    setErrorMessage(null);

    const normalizedEmail = email.trim().toLowerCase();
    if (!normalizedEmail || password.length < MIN_PASSWORD_LENGTH) {
      setErrorMessage("Enter an email and a password with at least 6 characters.");
      return;
    }

    setIsSubmitting(true);
    try {
      const supabase = createClient();
      const nextPath = getSafeNextPath();

      if (mode === "sign-in") {
        const { error } = await supabase.auth.signInWithPassword({
          email: normalizedEmail,
          password,
        });

        if (error) {
          throw error;
        }

        router.replace(nextPath);
        router.refresh();
        return;
      }

      const { data, error } = await supabase.auth.signUp({
        email: normalizedEmail,
        password,
        options: {
          emailRedirectTo: getEmailRedirectTo(nextPath),
        },
      });

      if (error) {
        throw error;
      }

      if (data.session) {
        router.replace(nextPath);
        router.refresh();
        return;
      }

      setStatusMessage("Check your email to finish account setup.");
    } catch (error) {
      setErrorMessage(getErrorMessage(error));
    } finally {
      setIsSubmitting(false);
    }
  }

  const submitLabel = mode === "sign-in" ? "Sign in" : "Create account";

  return (
    <main className="relative min-h-screen">
      <div className="border-b border-[var(--color-rule)]">
        <div className="mx-auto flex max-w-6xl items-center justify-between gap-4 px-8 py-3.5 text-[10px] uppercase tracking-[0.32em] text-[var(--color-ink-50)] md:px-12 lg:px-16">
          <Link
            href="/"
            className="inline-flex items-center gap-2.5 text-[var(--color-ink-80)] transition-colors hover:text-[var(--color-ink)]"
          >
            <span
              aria-hidden="true"
              className="inline-block h-1.5 w-1.5 rotate-45 bg-[var(--color-caret)]"
            />
            <span>Cofounder</span>
          </Link>
          <span className="inline-flex items-center gap-3">
            <span className="hidden sm:inline">Product auth</span>
          </span>
        </div>
      </div>

      <section className="mx-auto grid max-w-6xl gap-x-12 gap-y-14 px-8 pt-16 pb-24 md:grid-cols-12 md:px-12 md:pt-24 md:pb-32 lg:px-16">
        <div className="co-rise md:col-span-6" style={{ animationDelay: "60ms" }}>
          <p className="text-[10px] uppercase tracking-[0.32em] text-[var(--color-ink-40)]">
            Supabase / Email and password
          </p>
          <h1 className="mt-10 font-display text-[clamp(2.5rem,6vw,5rem)] font-normal leading-[1] tracking-normal text-[var(--color-ink)]">
            Sign in.
          </h1>
          <p className="mt-6 max-w-md text-balance text-[15px] leading-7 text-[var(--color-ink-70)]">
            Use the account attached to this product. New teammates can create one here when signup
            is enabled in Supabase.
          </p>
          <div className="mt-12 border-y border-[var(--color-rule)] py-5">
            <dl className="grid gap-4 text-[12px] text-[var(--color-ink-70)] sm:grid-cols-2">
              <div>
                <dt className="text-[10px] uppercase tracking-[0.22em] text-[var(--color-ink-40)]">
                  Method
                </dt>
                <dd className="mt-1 text-[var(--color-ink-90)]">Password</dd>
              </div>
              <div>
                <dt className="text-[10px] uppercase tracking-[0.22em] text-[var(--color-ink-40)]">
                  Session
                </dt>
                <dd className="mt-1 text-[var(--color-ink-90)]">Supabase SSR</dd>
              </div>
            </dl>
          </div>
        </div>

        <div
          className="co-rise md:col-span-6 md:border-l md:border-[var(--color-rule)] md:pl-10 lg:pl-14"
          style={{ animationDelay: "160ms" }}
        >
          <div className="max-w-md">
            <div
              role="tablist"
              aria-label="Authentication mode"
              className="grid grid-cols-2 border border-[var(--color-rule)] bg-[var(--color-paper)] p-1"
            >
              {(["sign-in", "sign-up"] as const).map((authMode) => (
                <button
                  key={authMode}
                  type="button"
                  role="tab"
                  aria-selected={mode === authMode}
                  onClick={() => {
                    setMode(authMode);
                    setStatusMessage(null);
                    setErrorMessage(null);
                  }}
                  className="px-4 py-2.5 text-[10px] uppercase tracking-[0.24em] text-[var(--color-ink-60)] transition-colors hover:text-[var(--color-ink)] aria-selected:bg-[var(--color-ink)] aria-selected:text-[var(--color-bg)]"
                >
                  {authMode === "sign-in" ? "Sign in" : "Sign up"}
                </button>
              ))}
            </div>

            <form onSubmit={handleSubmit} className="mt-8 space-y-5">
              <label className="block">
                <span className="text-[10px] uppercase tracking-[0.22em] text-[var(--color-ink-50)]">
                  Email
                </span>
                <input
                  type="email"
                  autoComplete="email"
                  required
                  value={email}
                  onChange={(event) => setEmail(event.target.value)}
                  className="mt-2 w-full border border-[var(--color-rule)] bg-[var(--color-paper)] px-4 py-3 text-[15px] text-[var(--color-ink)] outline-none transition-colors placeholder:text-[var(--color-ink-40)] focus:border-[var(--color-ink-40)] focus:bg-[var(--color-paper-raised)]"
                  placeholder="you@example.com"
                />
              </label>

              <label className="block">
                <span className="text-[10px] uppercase tracking-[0.22em] text-[var(--color-ink-50)]">
                  Password
                </span>
                <input
                  type="password"
                  autoComplete={mode === "sign-in" ? "current-password" : "new-password"}
                  required
                  minLength={MIN_PASSWORD_LENGTH}
                  value={password}
                  onChange={(event) => setPassword(event.target.value)}
                  className="mt-2 w-full border border-[var(--color-rule)] bg-[var(--color-paper)] px-4 py-3 text-[15px] text-[var(--color-ink)] outline-none transition-colors placeholder:text-[var(--color-ink-40)] focus:border-[var(--color-ink-40)] focus:bg-[var(--color-paper-raised)]"
                  placeholder="password"
                />
              </label>

              <button
                type="submit"
                disabled={isSubmitting}
                className="group inline-flex w-full items-center justify-center gap-3 border border-[var(--color-ink)] bg-[var(--color-ink)] px-5 py-3.5 text-[11px] uppercase tracking-[0.24em] text-[var(--color-bg)] transition-colors hover:bg-[var(--color-bg)] hover:text-[var(--color-ink)] disabled:cursor-not-allowed disabled:opacity-60"
              >
                <span>{isSubmitting ? "Working" : submitLabel}</span>
                {isSubmitting ? (
                  <Loader2 aria-hidden="true" className="h-3.5 w-3.5 animate-spin" />
                ) : (
                  <ArrowRight
                    aria-hidden="true"
                    className="h-3.5 w-3.5 transition-transform group-hover:translate-x-1"
                  />
                )}
              </button>

              <div aria-live="polite" className="min-h-6 text-[13px] leading-6">
                {statusMessage ? (
                  <p className="text-[var(--color-ink-70)]">{statusMessage}</p>
                ) : null}
                {errorMessage ? (
                  <p className="text-red-600 dark:text-red-300">{errorMessage}</p>
                ) : null}
              </div>
            </form>
          </div>
        </div>
      </section>
    </main>
  );
}

import { NextResponse } from "next/server";
import { createClient } from "@/lib/supabase/server";

function getSafeRedirectPath(requestUrl: URL, nextPath: string | null): string {
  if (!nextPath) {
    return "/";
  }

  try {
    const candidateUrl = new URL(nextPath, requestUrl.origin);
    if (candidateUrl.origin !== requestUrl.origin) {
      return "/";
    }
    if (!candidateUrl.pathname.startsWith("/")) {
      return "/";
    }

    return `${candidateUrl.pathname}${candidateUrl.search}`;
  } catch {
    return "/";
  }
}

export async function GET(request: Request) {
  const requestUrl = new URL(request.url);
  const code = requestUrl.searchParams.get("code");

  if (!code) {
    return NextResponse.redirect(new URL("/", requestUrl.origin));
  }

  const supabase = await createClient({ allowCookieWriteFailure: false });
  const { error } = await supabase.auth.exchangeCodeForSession(code);
  if (error) {
    return NextResponse.redirect(new URL("/", requestUrl.origin));
  }

  const nextPath = getSafeRedirectPath(requestUrl, requestUrl.searchParams.get("next"));
  return NextResponse.redirect(new URL(nextPath, requestUrl.origin));
}

import { type NextRequest, NextResponse } from "next/server";
import { updateSession } from "@/lib/supabase/proxy";
import { isSupabaseConfigured } from "@/lib/supabase/server-env";

// Paths that require a signed-in Supabase user. Everything else (landing,
// /pricing, /login, /auth/**, /api/**) stays public.
const PROTECTED_PATH_PREFIXES = ["/settings"];

function isProtectedPath(pathname: string): boolean {
  return PROTECTED_PATH_PREFIXES.some(
    (prefix) => pathname === prefix || pathname.startsWith(`${prefix}/`),
  );
}

function redirectToLogin(request: NextRequest, sessionResponse: NextResponse): NextResponse {
  const loginUrl = new URL("/login", request.url);
  loginUrl.searchParams.set("next", `${request.nextUrl.pathname}${request.nextUrl.search}`);
  const redirectResponse = NextResponse.redirect(loginUrl);
  // Preserve cookies set by updateSession (refresh / clear) on the redirect.
  sessionResponse.cookies.getAll().forEach(({ name, value, ...options }) => {
    redirectResponse.cookies.set(name, value, options);
  });
  return redirectResponse;
}

// Next.js middleware entry point (renamed `proxy` in this template — see
// config.matcher below). Session validation is dynamic, not commented out:
// a freshly provisioned repo with no Supabase env still runs `bun dev` and
// serves the seeded landing immediately (isSupabaseConfigured() is false, so
// every request passes through untouched). Gating turns on only when the
// browser-public pair NEXT_PUBLIC_SUPABASE_URL + NEXT_PUBLIC_SUPABASE_ANON_KEY
// is set — the same vars createClient()/login need. Server-only SUPABASE_URL /
// SUPABASE_ANON_KEY alone do not enable protection (login would still be
// unusable). Once those public vars are present, this refreshes the session
// on every request and redirects signed-out users away from protected paths.
export async function proxy(request: NextRequest) {
  if (!isSupabaseConfigured()) {
    return NextResponse.next({ request });
  }

  const { response, user } = await updateSession(request);

  if (isProtectedPath(request.nextUrl.pathname) && !user) {
    return redirectToLogin(request, response);
  }

  return response;
}

export const config = {
  matcher: ["/((?!_next/static|_next/image|favicon.ico|.*\\.(?:svg|png|jpg|jpeg|gif|webp)$).*)"],
};

const MISSING_SUPABASE_ENV_ERROR =
  "Missing NEXT_PUBLIC_SUPABASE_URL or NEXT_PUBLIC_SUPABASE_ANON_KEY";

export function getSupabaseEnv() {
  const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL;
  const supabaseAnonKey = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY;

  if (!supabaseUrl || !supabaseAnonKey) {
    throw new Error(MISSING_SUPABASE_ENV_ERROR);
  }

  return {
    supabaseUrl,
    supabaseAnonKey,
  };
}

const MISSING_SUPABASE_SERVER_ENV_ERROR =
  "Missing Supabase server env. Set SUPABASE_URL, GIC_SERVER_SUPABASE_URL, or NEXT_PUBLIC_SUPABASE_URL with SUPABASE_ANON_KEY or NEXT_PUBLIC_SUPABASE_ANON_KEY.";
const MISSING_SUPABASE_ADMIN_ENV_ERROR =
  "Missing Supabase admin env. Set SUPABASE_SERVICE_ROLE_KEY and a server Supabase URL.";

interface LocalService {
  alias?: unknown;
  port?: unknown;
  scheme?: unknown;
}

function getSandboxLocalSupabaseUrl(): string | undefined {
  const rawServices = process.env.GIC_BROWSER_LOCAL_SERVICES_JSON;
  if (!rawServices) {
    return undefined;
  }

  let services: unknown;
  try {
    services = JSON.parse(rawServices);
  } catch {
    return undefined;
  }

  if (!Array.isArray(services)) {
    return undefined;
  }

  for (const rawService of services) {
    if (!rawService || typeof rawService !== "object") {
      continue;
    }

    const service = rawService as LocalService;
    const alias = typeof service.alias === "string" ? service.alias.trim().toLowerCase() : "";
    if (alias !== "supabase") {
      continue;
    }

    const port = typeof service.port === "number" ? service.port : Number(service.port);
    if (!Number.isInteger(port) || port < 1 || port > 65535) {
      continue;
    }

    const scheme = service.scheme === "https" ? "https" : "http";
    return `${scheme}://127.0.0.1:${port}`;
  }

  return undefined;
}

function isBrowserServiceProxyUrl(value: string | undefined): boolean {
  if (!value) {
    return false;
  }

  try {
    return new URL(value).pathname.includes("/proxy/browser/service/");
  } catch {
    return false;
  }
}

function getServerSupabaseUrl(): string | undefined {
  const configuredServerUrl = process.env.SUPABASE_URL;
  const sandboxServerUrl = process.env.GIC_SERVER_SUPABASE_URL || getSandboxLocalSupabaseUrl();

  if (sandboxServerUrl) {
    return sandboxServerUrl;
  }

  if (configuredServerUrl && !isBrowserServiceProxyUrl(configuredServerUrl)) {
    return configuredServerUrl;
  }

  return process.env.NEXT_PUBLIC_SUPABASE_URL;
}

function getServerSupabaseAnonKey(): string | undefined {
  // Prefer the browser-public anon key so middleware session validation
  // matches createClient()/login (which always use NEXT_PUBLIC_*).
  return process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY || process.env.SUPABASE_ANON_KEY;
}

// Non-throwing counterpart to getSupabaseServerEnv() — use this to branch
// (e.g. in proxy.ts) on whether Supabase is wired up yet, without a try/catch.
// Gate on the browser-public pair that createClient()/login actually need;
// server-only SUPABASE_URL/ANON_KEY alone would enable /settings protection
// while leaving /login unable to authenticate.
export function isSupabaseConfigured(): boolean {
  return Boolean(process.env.NEXT_PUBLIC_SUPABASE_URL && process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY);
}

export function getSupabaseServerEnv() {
  const supabaseUrl = getServerSupabaseUrl();
  const supabaseAnonKey = getServerSupabaseAnonKey();

  if (!supabaseUrl || !supabaseAnonKey) {
    throw new Error(MISSING_SUPABASE_SERVER_ENV_ERROR);
  }

  return {
    supabaseUrl,
    supabaseAnonKey,
  };
}

export function getSupabaseAdminEnv() {
  const supabaseUrl = getServerSupabaseUrl();
  const supabaseServiceRoleKey = process.env.SUPABASE_SERVICE_ROLE_KEY;

  if (!supabaseUrl || !supabaseServiceRoleKey) {
    throw new Error(MISSING_SUPABASE_ADMIN_ENV_ERROR);
  }

  return {
    supabaseUrl,
    supabaseServiceRoleKey,
  };
}

import { createBrowserClient } from "@supabase/ssr";
import { getSupabaseEnv } from "./env";

export function createClient() {
  const { supabaseUrl, supabaseAnonKey } = getSupabaseEnv();

  return createBrowserClient(supabaseUrl, supabaseAnonKey);
}

import { createServerClient } from "@supabase/ssr";
import { cookies } from "next/headers";
import { getSupabaseServerEnv } from "./server-env";

interface CreateClientOptions {
  allowCookieWriteFailure?: boolean;
}

export async function createClient(options: CreateClientOptions = {}) {
  const cookieStore = await cookies();
  const allowCookieWriteFailure = options.allowCookieWriteFailure ?? true;
  const { supabaseUrl, supabaseAnonKey } = getSupabaseServerEnv();

  return createServerClient(supabaseUrl, supabaseAnonKey, {
    cookies: {
      getAll() {
        return cookieStore.getAll();
      },
      setAll(cookiesToSet) {
        try {
          cookiesToSet.forEach(({ name, value, options }) => {
            cookieStore.set(name, value, options);
          });
        } catch (error) {
          if (!allowCookieWriteFailure) {
            throw error;
          }

          // Server Components cannot always write cookies. The proxy refreshes
          // auth cookies for request lifecycles that need mutation.
        }
      },
    },
  });
}

import { createClient as createSupabaseClient } from "@supabase/supabase-js";
import { getSupabaseAdminEnv } from "./server-env";

export function createAdminClient() {
  if (typeof window !== "undefined") {
    throw new Error("createAdminClient can only be used on the server.");
  }

  const { supabaseUrl, supabaseServiceRoleKey } = getSupabaseAdminEnv();

  return createSupabaseClient(supabaseUrl, supabaseServiceRoleKey, {
    auth: {
      autoRefreshToken: false,
      detectSessionInUrl: false,
      persistSession: false,
    },
  });
}

import { createServerClient } from "@supabase/ssr";
import { type NextRequest, NextResponse } from "next/server";
import { getSupabaseServerEnv } from "./server-env";

export async function updateSession(request: NextRequest) {
  const { supabaseUrl, supabaseAnonKey } = getSupabaseServerEnv();
  let supabaseResponse = NextResponse.next({ request });

  const supabase = createServerClient(supabaseUrl, supabaseAnonKey, {
    cookies: {
      getAll() {
        return request.cookies.getAll();
      },
      setAll(cookiesToSet) {
        supabaseResponse = NextResponse.next({ request });
        cookiesToSet.forEach(({ name, value, options }) => {
          supabaseResponse.cookies.set(name, value, options);
        });
      },
    },
  });

  // Re-validates the session against Supabase (not just the cookie) so route
  // gating below can't be fooled by a stale/forged cookie.
  const { data } = await supabase.auth.getUser();

  return { response: supabaseResponse, user: data.user };
}
